package testutils.ptest2.org.apache.hive.ptest.execution.conf;

public class ExecutionContextConfiguration { public static final String WORKING_DIRECTORY = "workingDirectory" ; public static final String PROFILE_DIRECTORY = "profileDirectory" ; public static final String MAX_LOG_DIRS_PER_PROFILE = "maxLogDirectoriesPerProfile" ; private final ExecutionContextProvider mExecutionContextProvider ; private final String mWorkingDirectory ; private final String mGlobalLogDirectory ; private final String mProfileDirectory ; private final int mMaxLogDirectoriesPerProfile ; @ VisibleForTesting public ExecutionContextConfiguration ( Context context ) throws IOException { mWorkingDirectory = context . getString ( WORKING_DIRECTORY , "" ) . trim ( ) ; Preconditions . checkArgument ( ! mWorkingDirectory . isEmpty ( ) , WORKING_DIRECTORY + " is required" ) ; mProfileDirectory = context . getString ( PROFILE_DIRECTORY , "" ) . trim ( ) ; Preconditions . checkArgument ( ! mProfileDirectory . isEmpty ( ) , PROFILE_DIRECTORY + " is required" ) ; mGlobalLogDirectory = Dirs . create ( new File ( mWorkingDirectory , "logs" ) ) . getAbsolutePath ( ) ; mMaxLogDirectoriesPerProfile = context . getInteger ( MAX_LOG_DIRS_PER_PROFILE , 10 ) ; String executionContextProviderBuilder = context . getString ( "executionContextProvider" , FixedExecutionContextProvider . Builder . class . getName ( ) ) . trim ( ) ; try { Object builder = Class . forName ( executionContextProviderBuilder ) . newInstance ( ) ; if ( ! ( builder instanceof ExecutionContextProvider . Builder ) ) { throw new IllegalArgumentException ( "executionContextProvider must be of type " + ExecutionContextProvider . Builder . class . getName ( ) ) ; } mExecutionContextProvider = ( ( ExecutionContextProvider . Builder ) builder ) . build ( context , mWorkingDirectory ) ; } catch ( Exception e ) { throw Throwables . propagate ( e ) ; } } public int getMaxLogDirectoriesPerProfile ( ) { return mMaxLogDirectoriesPerProfile ; } public String getWorkingDirectory ( ) { return mWorkingDirectory ; } public String getGlobalLogDirectory ( ) { return mGlobalLogDirectory ; } public String getProfileDirectory ( ) { return mProfileDirectory ; } public ExecutionContextProvider getExecutionContextProvider ( ) { return mExecutionContextProvider ; } public static ExecutionContextConfiguration fromInputStream ( InputStream inputStream ) throws IOException { Properties properties = new Properties ( ) ; properties . load ( inputStream ) ; Context context = new Context ( Maps . fromProperties ( properties ) ) ; return new ExecutionContextConfiguration ( context ) ; } public static ExecutionContextConfiguration fromFile ( String file ) throws IOException { InputStream in = new FileInputStream ( file ) ; try { return fromInputStream ( in ) ; } finally { in . close ( ) ; } } }